function injectOgTags(html, path, url) {
  const meta = OG_META[path];
  if (!meta) return html;

  const tags = [
    `<meta property="og:title" content="${meta.title}">`,
    `<meta property="og:description" content="${meta.description}">`,
    `<meta property="og:image" content="${meta.image}">`,
    `<meta property="og:url" content="${url}">`,
    `<meta property="og:type" content="website">`,
    `<meta name="twitter:card" content="summary_large_image">`,
    `<meta name="twitter:title" content="${meta.title}">`,
    `<meta name="twitter:description" content="${meta.description}">`,
    `<meta name="twitter:image" content="${meta.image}">`,
    `<meta name="twitter:site" content="@ollie_exo">`,
  ].join('\n    ');

  if (html.includes('<head>')) {
    return html.replace('<head>', `<head>\n    ${tags}`);
  } else if (html.includes('<HEAD>')) {
    return html.replace('<HEAD>', `<HEAD>\n    ${tags}`);
  }
  return `<html><head>${tags}</head><body>${html}</body></html>`;
}

export default {
  async fetch(request) {
    const url = new URL(request.url);

    // ─── ExoHost: serve {name}.exohost.xyz ───
    if (url.hostname.endsWith(EXOHOST_DOMAIN) && url.hostname !== EXOHOST_DOMAIN && url.hostname !== `www.${EXOHOST_DOMAIN}`) {
      const exoResponse = await handleExoHost(request);
      if (exoResponse) return exoResponse;
    }

    let path = url.pathname.replace(/\/+$/, '') || '/';

    // Serve OG images
    if (OG_IMAGES[path]) {
      const bytes = Uint8Array.from(atob(OG_IMAGES[path]), c => c.charCodeAt(0));
      return new Response(bytes, {
        headers: {
          'Content-Type': 'image/png',
          'Cache-Control': 'public, max-age=86400',
        },
      });
    }


    // Farcaster Mini App manifest
    if (path === '/.well-known/farcaster.json') {
      return new Response(JSON.stringify({
        accountAssociation: {
          header: 'eyJmaWQiOjI4NDgwMTksInR5cGUiOiJjdXN0b2R5Iiwia2V5IjoiMHhlYTlkRDY5MEY4MDlFNzNiOTEzNjE1NTczNjc1RDE1RDBGQjRBRUIzIn0',
          payload: 'eyJkb21haW4iOiJleG9hZ2VudC54eXoifQ',
          signature: 'cVaZxlJHzjQg5lOzq45abGhksLb8v5PkQMXmKS4p9TFb6DSoNtwDskMDrC1h3+8ONlJ5yXkav5+9c5uodP24mxw=',
        },
        miniapp: {
          version: '1',
          name: 'Agent Outlier',
          homeUrl: 'https://exoagent.xyz/play',
          iconUrl: 'https://files.catbox.moe/d8bqpm.png',
          splashImageUrl: 'https://files.catbox.moe/d8bqpm.png',
          splashBackgroundColor: '#000000',
          subtitle: 'Beat the bots. Win ETH.',
          description: 'First AI agent game on Base. Pick numbers, outsmart agents, earn ELO.',
          primaryCategory: 'games',
          tags: ['onchain', 'base', 'ai-agents', 'strategy'],
          requiredChains: ['eip155:8453'],
          imageUrl: 'https://exoagent.xyz/og/exo-home.png',
          buttonTitle: 'Play Outlier',
          ogTitle: 'Agent Outlier',
          ogDescription: 'First AI agent game on Base. Pick numbers, outsmart agents, earn ELO. Exoskeleton required.',
          ogImageUrl: 'https://exoagent.xyz/og/exo-home.png',
        },
      }), {
        headers: {
          'Content-Type': 'application/json',
          'Cache-Control': 'public, max-age=3600',
          'Access-Control-Allow-Origin': '*',
        },
      });
    }

    // Strip .html extension
    path = path.replace(/\.html$/, '');
    if (path === '/index') path = '/';

    // Handle redirects for old pages that moved in redesign
    if (REDIRECTS[path]) {
      return Response.redirect(`https://${url.hostname}${REDIRECTS[path]}`, 301);
    }

    const key = ROUTES[path];
    if (!key) {
      return Response.redirect(`https://${url.hostname}/`, 302);
    }

    // Fetch from storedon.net and serve as HTML
    const storeUrl = `${BASE}/${key}`;
    const response = await fetch(storeUrl);
    let html = await response.text();

    // Inject OG meta tags for social previews
    html = injectOgTags(html, path, url.href);

    return new Response(html, {
      headers: {
        'Content-Type': 'text/html; charset=utf-8',
        'Cache-Control': 'public, max-age=300',
        'X-Content-Type-Options': 'nosniff',
      },
    });
  },
};
